"use client";

import { useState, useEffect } from "react";
import { useParams } from "next/navigation";
import { fetchStockPrice, fetchStockChart } from "@/lib/api";
import { addWatchlist, removeWatchlist, isInWatchlist } from "@/lib/watchlist";
import { supabase } from "@/utils/supabase/client";
import type { StockPrice, ChartResponse } from "@/types";
import LoadingSpinner from "@/components/ui/LoadingSpinner";
import ErrorMessage from "@/components/ui/ErrorMessage";
import StockChart from "@/components/stock/StockChart";
import StockInfo from "@/components/stock/StockInfo";
import Link from "next/link";
import { ArrowLeft, Sparkles } from "lucide-react";

export default function StockDetailPage() {
  const { code } = useParams<{ code: string }>();
  const [price, setPrice] = useState<StockPrice | null>(null);
  const [chart, setChart] = useState<ChartResponse | null>(null);
  const [period, setPeriod] = useState("3m");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [inWatchlist, setInWatchlist] = useState(false);
  const [watchlistLoading, setWatchlistLoading] = useState(false);
  const [userChecked, setUserChecked] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  useEffect(() => {
    setLoading(true);
    setError("");
    Promise.all([
      fetchStockPrice(code),
      fetchStockChart(code, period),
    ])
      .then(([p, c]) => { setPrice(p); setChart(c); })
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false));
  }, [code, period]);

  useEffect(() => {
    supabase.auth.getUser().then(({ data: { user } }) => {
      setUserChecked(true);
      setIsLoggedIn(!!user);
      if (user) isInWatchlist(code).then(setInWatchlist);
    });
  }, [code]);

  const toggleWatchlist = () => {
    if (!price) return;
    setWatchlistLoading(true);
    (inWatchlist ? removeWatchlist(code) : addWatchlist(code, price.name))
      .then((res) => {
        if (res.ok) setInWatchlist(!inWatchlist);
        else if (res.error) setError(res.error);
      })
      .finally(() => setWatchlistLoading(false));
  };

  if (loading) return <LoadingSpinner />;
  if (error) return <ErrorMessage message={error} />;
  if (!price) return null;

  return (
    <div className="space-y-6 max-w-2xl mx-auto">
      <Link href="/stock" className="inline-flex items-center text-gray-400 hover:text-white text-sm transition-colors">
        <ArrowLeft className="w-4 h-4 mr-1" /> 검색으로
      </Link>

      <StockInfo
        price={price}
        inWatchlist={inWatchlist}
        isLoggedIn={isLoggedIn}
        userChecked={userChecked}
        watchlistLoading={watchlistLoading}
        onToggleWatchlist={toggleWatchlist}
      />

      {/* AI 분석 페이지로 이동 */}
      <Link
        href={`/stock/${code}/analysis`}
        className="w-full py-3 bg-skyblue/20 hover:bg-skyblue/30 border border-skyblue/30 rounded-xl text-skyblue font-medium transition-colors flex items-center justify-center gap-2"
      >
        <Sparkles className="w-5 h-5" />
        AI로 분석하기
      </Link>

      {/* 차트 기간 선택 */}
      <div>
        <div className="flex gap-2 mb-3">
          {["1m", "3m", "6m", "1y"].map((p) => (
            <button
              key={p}
              onClick={() => setPeriod(p)}
              className={`px-3 py-1 rounded-lg text-sm transition-colors ${
                period === p ? "bg-skyblue text-white" : "bg-white/5 text-gray-400 hover:text-white"
              }`}
            >
              {p === "1m" ? "1개월" : p === "3m" ? "3개월" : p === "6m" ? "6개월" : "1년"}
            </button>
          ))}
        </div>

        {chart && chart.data.length > 0 && (
          <div className="bg-white/5 border border-white/10 rounded-xl p-4">
            <StockChart data={chart.data} className="w-full" />
            <div className="flex justify-between mt-2 text-[10px] text-gray-500">
              <span>{chart.data[0]?.date}</span>
              <span>{chart.data[chart.data.length - 1]?.date}</span>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
